// 1. ดึงข้อมูลทั้งหมดที่เพิ่งเซฟลง Sheet
const allPosts = $input.all().map(item => item.json);

// 2. คำนวณสรุปข้อมูล (KPIs)
const totalPosts = allPosts.length;
// นับจำนวนคู่แข่งที่ไม่ซ้ำกันที่มีการโพสต์วันนี้
const uniqueCompetitors = [...new Set(allPosts.map(p => p.pageName || 'Unknown'))].length;
// สร้างวันที่แบบไทยสวยๆ
const todayStr = new Date().toLocaleDateString('th-TH', { year: 'numeric', month: 'long', day: 'numeric' });

// 3. สร้างโครงสร้าง HTML (ดัดแปลงจากเทมเพลต UPMY SKILLS ให้รองรับ Email)
let html = `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<style>
  body { font-family: 'Tahoma', 'Sarabun', sans-serif; color: #1F2937; background: #FFFFFF; line-height: 1.6; margin: 0; padding: 20px; }

  /* Header & Branding */
  .brand-logo { font-size: 20px; font-weight: bold; color: #1B3A5F; letter-spacing: 2px; }
  .brand-logo span { color: #C9A961; }
  .page-header { border-bottom: 2px solid #C9A961; padding-bottom: 10px; margin-bottom: 20px; }
  .report-date { font-size: 12px; color: #4B5563; }

  /* Section Headers */
  .section-header { background: linear-gradient(135deg, #1B3A5F, #0F2440); color: #FFFFFF; padding: 12px 20px; border-radius: 6px; margin-bottom: 16px; font-weight: bold; font-size: 16px; }

  /* KPI Cards (Email safe layout) */
  .kpi-container { margin-bottom: 20px; width: 100%; }
  .kpi-card { background: #E8EDF3; border-radius: 8px; padding: 16px; text-align: center; border-left: 4px solid #C9A961; display: inline-block; width: 45%; box-sizing: border-box; }
  .kpi-value { font-size: 28px; font-weight: bold; color: #1B3A5F; margin-bottom: 4px; }
  .kpi-label { font-size: 12px; color: #4B5563; }

  /* Tables */
  .data-table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; }
  .data-table th { background: #1B3A5F; color: #FFFFFF; padding: 12px; text-align: left; border-radius: 4px 4px 0 0;}
  .data-table td { padding: 12px; border-bottom: 1px solid #D1D5DB; vertical-align: top; }
  .data-table tr:nth-child(even) td { background: #F5F6F8; }

  .fb-link { display: inline-block; background: #E8EDF3; color: #1B3A5F; padding: 6px 12px; text-decoration: none; border-radius: 4px; font-weight: bold; font-size: 11px; }
  .like-badge { display: inline-block; background: #C9A961; color: #FFFFFF; padding: 2px 8px; border-radius: 12px; font-size: 10px; font-weight: bold; margin-top: 4px; }
</style>
</head>
<body>

  <div class="page-header">
    <div class="brand-logo">UPMY <span>SKILLS</span></div>
    <div class="report-date">Daily Competitor Social Media Update | ${todayStr}</div>
  </div>

  <div class="section-header">
    📊 EXECUTIVE SUMMARY | สรุปภาพรวมความเคลื่อนไหว
  </div>

  <div class="kpi-container">
    <div class="kpi-card" style="margin-right: 2%;">
      <div class="kpi-value">${totalPosts}</div>
      <div class="kpi-label">Total Active Posts<br>จำนวนโพสต์ที่พบวันนี้</div>
    </div>
    <div class="kpi-card">
      <div class="kpi-value">${uniqueCompetitors}</div>
      <div class="kpi-label">Active Competitors<br>จำนวนคู่แข่งที่เคลื่อนไหว</div>
    </div>
  </div>

  <div class="section-header">
    📝 POST DETAILS | รายละเอียดเนื้อหาและโปรโมชั่น
  </div>

  <table class="data-table">
    <thead>
      <tr>
        <th style="width: 25%;">Resort / คู่แข่ง</th>
        <th style="width: 55%;">Content / เนื้อหาโพสต์</th>
        <th style="width: 20%;">Action</th>
      </tr>
    </thead>
    <tbody>
`;

// 4. วนลูปข้อมูลแต่ละโพสต์มาใส่ในตาราง
allPosts.forEach(post => {
  // Mapping ตัวแปรให้ตรงกับ Google Sheets ขาเข้า
  const name = post.pageName || 'Unknown Resort';

  // แปลง \n ให้เป็น <br> เพื่อให้ข้อความขึ้นบรรทัดใหม่ได้ถูกต้องใน HTML
  let content = post.text || '-';
  content = content.replace(/\n/g, '<br>'); 

  const link = post.url || '#';
  const likes = post.likes !== undefined ? post.likes : 0;

  html += `
      <tr>
        <td>
          <strong style="color: #1B3A5F; font-size: 13px;">${name}</strong><br>
          <div class="like-badge">👍 ${likes} Likes</div>
        </td>
        <td style="color: #4B5563; line-height: 1.5;">${content}</td>
        <td>
          <a href="${link}" class="fb-link" target="_blank">View Post ↗</a>
        </td>
      </tr>
  `;
});

// 5. ปิดท้าย HTML
html += `
    </tbody>
  </table>

  <div style="text-align: center; margin-top: 30px; border-top: 1px solid #D1D5DB; padding-top: 15px;">
    <div class="brand-logo" style="font-size: 14px;">UPMY <span>SKILLS</span></div>
    <div style="font-size: 10px; color: #4B5563; margin-top: 5px;">Automated Competitor Intelligence by AI Workflow</div>
    <div style="font-size: 10px; color: #4B5563;">Confidential Report</div>
  </div>

</body>
</html>
`;

// 6. ส่งค่าออกไปให้โหนด Gmail
return {
  json: {
    html_report: html,
    subject_date: todayStr
  }
};
